static const uint8_t *SoundPt;
static uint32_t SoundCount;

void SysTick_IntArm(uint32_t period, uint32_t priority){
  SysTick->CTRL = 0;            // disable during setup
  SysTick->LOAD = period - 1;   // reload value for desired frequency
  SysTick->VAL  = 0;            // clear current count
  NVIC_SetPriority(SysTick_IRQn, priority);
  SysTick->CTRL = 0x05;         // enable counter, processor clock; interrupt off until Sound_Start
}

// initialize a 11kHz SysTick, however no sound should be started
// initialize any global variables
// Initialize the 5-bit DAC
void Sound_Init(void){
  SoundPt    = 0;
  SoundCount = 0;
  DAC5_Init();
  SysTick_IntArm(80000000 / 11000, 2); // 11kHz at 80MHz bus clock
}

void SysTick_Handler(void){ // called at 11 kHz
  if(SoundCount > 0){
    DAC5_Out((*SoundPt) >> 3);  // 8-bit sample -> 5-bit DAC (0-31)
    SoundPt++;
    SoundCount--;
    if(SoundCount == 0){
      SysTick->CTRL &= ~0x02;   // disable interrupt when sound finishes
      DAC5_Out(16);             // output midpoint (silence)
    }
  }
}

//******* Sound_Start ************
// This function does not output to the DAC.
// Rather, it sets a pointer and counter, and then enables the SysTick interrupt.
// It starts the sound, and the SysTick ISR does the output
// feel free to change the parameters
// Sound should play once and stop
// Input: pt is a pointer to an array of DAC outputs
//        count is the length of the array
// Output: none
// special cases: as you wish to implement
void Sound_Start(const uint8_t *pt, uint32_t count){
  SoundPt    = pt;
  SoundCount = count;
  SysTick->CTRL |= 0x02;        // enable SysTick interrupt to start playback
}

void Sound_Shoot(void){
  Sound_Start(shoot, 4080);
}
void Sound_Killed(void){
  Sound_Start(invaderkilled, 3377);
}
void Sound_Explosion(void){
  Sound_Start(explosion, 2000);
}

